    66→/// Batch: update icons for every state dir + .bop under .cards/.
    67→pub fn cmd_icons_sync(root: &Path) -> anyhow::Result<()> {
    68→    if !cfg!(target_os = "macos") {
    69→        println!("icons: macOS only");
    70→        return Ok(());
    71→    }
    72→    let mut n_cards = 0usize;
    73→    let mut n_dirs = 0usize;
    74→    let mut n_terminal_cards = 0usize;
    75→
    76→    // Top-level state dirs
    77→    sync_icons_in_root(root, &mut n_cards, &mut n_dirs, &mut n_terminal_cards);
    78→
    79→    // team-* subdirs
    80→    for entry in fs::read_dir(root)? {
    81→        let team = entry?.path();
    82→        if team.is_dir()
    83→            && team
    84→                .file_name()
    85→                .and_then(|n| n.to_str())
    86→                .map(|n| n.starts_with("team-"))
    87→                .unwrap_or(false)
    88→        {
    89→            sync_icons_in_root(&team, &mut n_cards, &mut n_dirs, &mut n_terminal_cards);
    90→        }
    91→    }
    92→    println!(
    93→        "✓ icons synced: {} state dirs, {} cards ({} terminal cards compression-refreshed)",
    94→        n_dirs, n_cards, n_terminal_cards
    95→    );
    96→    Ok(())
    97→}
