    99→/// FSEvents watcher (foreground): update icon immediately when any .bop dir moves.
   100→pub fn cmd_icons_watch(root: &Path) -> anyhow::Result<()> {
   101→    use notify::{Config, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
   102→
   103→    if !cfg!(target_os = "macos") {
   104→        println!("icons watch: macOS only");
   105→        return Ok(());
   106→    }
   107→
   108→    let cards_dir = root.to_path_buf();
   109→    let (tx, rx) = std::sync::mpsc::channel();
   110→    let mut watcher = RecommendedWatcher::new(tx, Config::default())?;
   111→    watcher.watch(&cards_dir, RecursiveMode::Recursive)?;
   112→
   113→    println!(
   114→        "bop icons watch — watching {} for card moves",
   115→        cards_dir.display()
   116→    );
   117→    println!("Ctrl+C to stop\n");
   118→
   119→    for res in rx {
   120→        let event = match res {
   121→            Ok(e) => e,
   122→            Err(e) => {
   123→                eprintln!("watch error: {}", e);
   124→                continue;
   125→            }
   126→        };
   127→
   128→        // Only care about create/rename events on .bop directories
   129→        let is_relevant = matches!(
   130→            event.kind,
   131→            EventKind::Create(_) | EventKind::Modify(notify::event::ModifyKind::Name(_))
   132→        );
   133→        if !is_relevant {
   134→            continue;
   135→        }
   136→
   137→        for path in &event.paths {
   138→            if path.extension().and_then(|e| e.to_str()) == Some("bop") && path.is_dir() {
   139→                set_card_icon(path);
   140→                quicklook::sync_card_action_links(path);
   141→                quicklook::compress_card(path);
   142→                println!(
   143→                    "  icon/links/compression updated: {}",
   144→                    path.file_name().unwrap_or_default().to_string_lossy()
   145→                );
   146→            }
   147→        }
   148→    }
   149→    Ok(())
   150→}
